package pl.msurvival.keys;
import org.bukkit.*;import org.bukkit.command.*;import org.bukkit.configuration.file.*;import org.bukkit.enchantments.*;import org.bukkit.entity.*;import org.bukkit.event.*;import org.bukkit.event.inventory.*;import org.bukkit.event.player.*;import org.bukkit.inventory.*;import org.bukkit.inventory.meta.*;import org.bukkit.persistence.*;import org.bukkit.plugin.java.JavaPlugin;import java.io.*;import java.util.*;
public final class MSurvivalKeys extends JavaPlugin implements Listener{private File f;private YamlConfiguration data;private NamespacedKey kt,ak;private final Random r=new Random();public void onEnable(){saveDefaultConfig();f=new File(getDataFolder(),"data.yml");if(!f.exists())try{getDataFolder().mkdirs();f.createNewFile();}catch(Exception e){e.printStackTrace();}data=YamlConfiguration.loadConfiguration(f);kt=new NamespacedKey(this,"key_type");ak=new NamespacedKey(this,"action");Bukkit.getPluginManager().registerEvents(this,this);}public void onDisable(){save();}public boolean onCommand(CommandSender s,Command c,String l,String[] a){String cmd=c.getName().toLowerCase(Locale.ROOT);if(cmd.equals("keysmenu")){if(s instanceof Player p)openKeys(p);return true;}if(cmd.equals("kits")){if(s instanceof Player p)openKits(p);return true;}if(cmd.equals("weeklykey")){if(s instanceof Player p)weekly(p);return true;}if(cmd.equals("keyadmin")){if(!s.hasPermission("msurvival.keys.admin")){s.sendMessage(msg("no-permission"));return true;}if(a.length<3){s.sendMessage(color("&c/keyadmin <give|item> <gracz> <klucz> [ilosc]"));return true;}String mode=a[0].toLowerCase(Locale.ROOT),player=a[1],key=norm(a[2]);int amt=a.length>=4?parse(a[3]):1;if(!getConfig().contains("keys."+key)){s.sendMessage(color("&cNie ma klucza."));return true;}if(mode.equals("give")){addV(player,key,amt);s.sendMessage(color(msg("admin-give").replace("%amount%",String.valueOf(amt)).replace("%key%",display(key)).replace("%player%",player)));return true;}if(mode.equals("item")){Player t=Bukkit.getPlayerExact(player);if(t!=null)t.getInventory().addItem(keyItem(key,amt));return true;}}return true;}private void openKeys(Player p){Inventory inv=Bukkit.createInventory(null,54,color("&6&lKLUCZE SERWERA"));fill(inv);inv.setItem(4,gui(Material.CHEST,"&a&lCotygodniowy klucz","weekly",List.of("&7Kliknij, aby odebrać.")));int slot=10;for(String key:getConfig().getConfigurationSection("keys").getKeys(false)){inv.setItem(slot,gui(Material.TRIPWIRE_HOOK,display(key),"withdraw:"+key,List.of("&7Wirtualne: &e"+getV(p.getName(),key),"&7Fizyczne: &e"+countP(p,key),"","&aKliknij, aby wyjąć 1 klucz","&cTylko na Survivalu")));slot++;if(slot==17||slot==26||slot==35)slot+=2;}p.openInventory(inv);}private void openKits(Player p){Inventory inv=Bukkit.createInventory(null,27,color("&b&lE-KITY ZA KLUCZE"));fill(inv);kitB(inv,10,Material.STONE_PICKAXE,"klasyczny","&f&lE-Kit Klasyczny");kitB(inv,11,Material.IRON_CHESTPLATE,"zelazny","&7&lE-Kit Żelazny");kitB(inv,12,Material.DIAMOND_CHESTPLATE,"diamentowy","&b&lE-Kit Diamentowy");kitB(inv,13,Material.DIAMOND_SWORD,"epic","&5&lE-Kit Epic");kitB(inv,14,Material.NETHERITE_CHESTPLATE,"legendarny","&6&lE-Kit Legendarny");kitB(inv,15,Material.NETHER_STAR,"mityczny","&d&lE-Kit Mityczny");kitB(inv,16,Material.DRAGON_EGG,"boski","&4&lE-Kit Boski");p.openInventory(inv);}private void kitB(Inventory inv,int slot,Material m,String key,String name){inv.setItem(slot,gui(m,name,"kit:"+key,List.of("&7Wymagany: "+display(key),"","&aKliknij, aby odebrać")));}@EventHandler public void click(InventoryClickEvent e){if(!(e.getWhoClicked() instanceof Player p))return;String title=e.getView().getTitle();if(!title.equals(color("&6&lKLUCZE SERWERA"))&&!title.equals(color("&b&lE-KITY ZA KLUCZE")))return;e.setCancelled(true);String a=act(e.getCurrentItem());if(a==null)return;p.closeInventory();if(a.equals("weekly"))weekly(p);else if(a.startsWith("withdraw:"))withdraw(p,a.substring(9));else if(a.startsWith("kit:"))openKit(p,a.substring(4));}@EventHandler public void rc(PlayerInteractEvent e){if(keyType(e.getItem())!=null){e.setCancelled(true);e.getPlayer().sendMessage(msg("disabled-ppm"));}}private void weekly(Player p){long cd=getConfig().getLong("settings.weekly-cooldown-seconds",604800)*1000L,last=data.getLong(path(p.getName())+".weekly",0),left=cd-(System.currentTimeMillis()-last);if(last>0&&left>0){p.sendMessage(msg("cooldown").replace("%time%",time(left)));return;}String key=roll();data.set(path(p.getName())+".weekly",System.currentTimeMillis());addV(p.getName(),key,1);p.sendMessage(color(msg("claimed").replace("%key%",display(key))));p.playSound(p.getLocation(),Sound.ENTITY_PLAYER_LEVELUP,1,1);}private void withdraw(Player p,String key){key=norm(key);if(!isSurvival(p)){p.sendMessage(msg("only-survival"));return;}if(getV(p.getName(),key)<=0){p.sendMessage(color(msg("no-key").replace("%key%",display(key))));return;}addV(p.getName(),key,-1);p.getInventory().addItem(keyItem(key,1));p.sendMessage(color(msg("withdrawn").replace("%key%",display(key))));}private void openKit(Player p,String key){key=norm(key);if(!isSurvival(p)){p.sendMessage(msg("only-survival"));return;}if(!take(p,key)){p.sendMessage(color(msg("no-key").replace("%key%",display(key))));return;}giveKit(p,key);p.sendMessage(color(msg("opened").replace("%kit%",key)));p.playSound(p.getLocation(),Sound.ENTITY_PLAYER_LEVELUP,1,1);}private boolean take(Player p,String key){for(int i=0;i<p.getInventory().getSize();i++){ItemStack it=p.getInventory().getItem(i);if(key.equals(keyType(it))){if(it.getAmount()<=1)p.getInventory().setItem(i,null);else it.setAmount(it.getAmount()-1);return true;}}if(getV(p.getName(),key)>0){addV(p.getName(),key,-1);return true;}return false;}private void giveKit(Player p,String key){if(key.equals("klasyczny")){p.getInventory().addItem(new ItemStack(Material.BREAD,32),named(Material.STONE_SWORD,"&f&lKlasyczny Miecz"),named(Material.STONE_PICKAXE,"&f&lKlasyczny Kilof"));return;}boolean iron=key.equals("zelazny"),dia=key.equals("diamentowy")||key.equals("epic");Material sword=iron?Material.IRON_SWORD:dia?Material.DIAMOND_SWORD:Material.NETHERITE_SWORD;String name=switch(key){case "zelazny"->"&7&lŻelazny";case "diamentowy"->"&b&lDiamentowy";case "epic"->"&5&lEpic";case "legendarny"->"&6&lLegendarny";case "mityczny"->"&d&lMityczny";default->"&4&lBoski";};Material h=iron?Material.IRON_HELMET:dia?Material.DIAMOND_HELMET:Material.NETHERITE_HELMET,c=iron?Material.IRON_CHESTPLATE:dia?Material.DIAMOND_CHESTPLATE:Material.NETHERITE_CHESTPLATE,l=iron?Material.IRON_LEGGINGS:dia?Material.DIAMOND_LEGGINGS:Material.NETHERITE_LEGGINGS,b=iron?Material.IRON_BOOTS:dia?Material.DIAMOND_BOOTS:Material.NETHERITE_BOOTS,pick=iron?Material.IRON_PICKAXE:dia?Material.DIAMOND_PICKAXE:Material.NETHERITE_PICKAXE,axe=iron?Material.IRON_AXE:dia?Material.DIAMOND_AXE:Material.NETHERITE_AXE,sh=iron?Material.IRON_SHOVEL:dia?Material.DIAMOND_SHOVEL:Material.NETHERITE_SHOVEL,hoe=iron?Material.IRON_HOE:dia?Material.DIAMOND_HOE:Material.NETHERITE_HOE;p.getInventory().addItem(armor(h,name+" Hełm",false),armor(c,name+" Napierśnik",false),armor(l,name+" Spodnie",false),armor(b,name+" Buty",true),sword(sword,name+" Miecz"),tool(pick,name+" Kilof"),tool(axe,name+" Siekiera"),tool(sh,name+" Łopata"),tool(hoe,name+" Motyka"),bow(name+" Łuk"),new ItemStack(Material.GOLDEN_APPLE,key.equals("boski")?64:16),new ItemStack(Material.TOTEM_OF_UNDYING,key.equals("boski")?6:2));if(key.equals("boski"))p.getInventory().addItem(crossbow("&4&lBoska Kusza"),trident("&4&lBoski Trójząb"),elytra("&4&lBoskie Elytry"),new ItemStack(Material.ENCHANTED_GOLDEN_APPLE,16),new ItemStack(Material.FIREWORK_ROCKET,64));}private ItemStack armor(Material m,String n,boolean boots){ItemStack i=ench(m,n);add(i,"protection",4);add(i,"unbreaking",3);add(i,"mending",1);if(boots){add(i,"feather_falling",4);add(i,"depth_strider",3);add(i,"soul_speed",3);}return i;}private ItemStack sword(Material m,String n){ItemStack i=ench(m,n);add(i,"sharpness",5);add(i,"fire_aspect",2);add(i,"looting",3);add(i,"sweeping_edge",3);add(i,"unbreaking",3);add(i,"mending",1);return i;}private ItemStack tool(Material m,String n){ItemStack i=ench(m,n);add(i,"efficiency",5);add(i,"fortune",3);add(i,"unbreaking",3);add(i,"mending",1);return i;}private ItemStack bow(String n){ItemStack i=ench(Material.BOW,n);add(i,"power",5);add(i,"punch",2);add(i,"flame",1);add(i,"infinity",1);add(i,"unbreaking",3);return i;}private ItemStack crossbow(String n){ItemStack i=ench(Material.CROSSBOW,n);add(i,"quick_charge",3);add(i,"multishot",1);add(i,"piercing",4);add(i,"unbreaking",3);add(i,"mending",1);return i;}private ItemStack trident(String n){ItemStack i=ench(Material.TRIDENT,n);add(i,"loyalty",3);add(i,"impaling",5);add(i,"channeling",1);add(i,"unbreaking",3);add(i,"mending",1);return i;}private ItemStack elytra(String n){ItemStack i=ench(Material.ELYTRA,n);add(i,"unbreaking",3);add(i,"mending",1);return i;}private ItemStack ench(Material m,String n){return named(m,n);}private void add(ItemStack i,String e,int lvl){Enchantment en=Enchantment.getByKey(NamespacedKey.minecraft(e));if(en!=null)i.addUnsafeEnchantment(en,lvl);}private ItemStack keyItem(String key,int amt){ItemStack i=new ItemStack(Material.valueOf(getConfig().getString("key-item.material","TRIPWIRE_HOOK")),amt);ItemMeta m=i.getItemMeta();m.setDisplayName(color("&6&l✦ "+display(key)+" &6&l✦"));m.setLore(List.of(color("&7Klucz do E-Kita."),color("&cNie klikaj PPM."),color("&6&lMSURVIVAL")));m.addEnchant(Enchantment.UNBREAKING,1,true);m.addItemFlags(ItemFlag.HIDE_ENCHANTS,ItemFlag.HIDE_ATTRIBUTES);m.getPersistentDataContainer().set(kt,PersistentDataType.STRING,key);i.setItemMeta(m);return i;}private ItemStack gui(Material m,String n,String a,List<String> lore){ItemStack i=named(m,n);ItemMeta im=i.getItemMeta();ArrayList<String> lo=new ArrayList<>();for(String x:lore)lo.add(color(x));im.setLore(lo);im.getPersistentDataContainer().set(ak,PersistentDataType.STRING,a);i.setItemMeta(im);return i;}private ItemStack named(Material m,String n){ItemStack i=new ItemStack(m);ItemMeta im=i.getItemMeta();im.setDisplayName(color(n));im.setLore(List.of(color("&8━━━━━━━━━━━━━━━━"),color("&7Przedmiot z E-Kita"),color("&6&lMSURVIVAL"),color("&8━━━━━━━━━━━━━━━━")));i.setItemMeta(im);return i;}private void fill(Inventory inv){ItemStack g=named(Material.BLACK_STAINED_GLASS_PANE," ");for(int i=0;i<inv.getSize();i++)inv.setItem(i,g);}private String act(ItemStack i){return i==null||!i.hasItemMeta()?null:i.getItemMeta().getPersistentDataContainer().get(ak,PersistentDataType.STRING);}private String keyType(ItemStack i){return i==null||!i.hasItemMeta()?null:i.getItemMeta().getPersistentDataContainer().get(kt,PersistentDataType.STRING);}private boolean isSurvival(Player p){return p.getWorld().getName().equalsIgnoreCase(getConfig().getString("settings.survival-world","world"));}private int countP(Player p,String key){int a=0;for(ItemStack i:p.getInventory())if(key.equals(keyType(i)))a+=i.getAmount();return a;}private int getV(String p,String k){return data.getInt(path(p)+".keys."+norm(k),0);}private void addV(String p,String k,int a){String path=path(p)+".keys."+norm(k);data.set(path,Math.max(0,data.getInt(path,0)+a));save();}private String roll(){int total=0;for(String k:getConfig().getConfigurationSection("weekly").getKeys(false))total+=getConfig().getInt("weekly."+k);int roll=r.nextInt(Math.max(1,total))+1,cur=0;for(String k:getConfig().getConfigurationSection("weekly").getKeys(false)){cur+=getConfig().getInt("weekly."+k);if(roll<=cur)return norm(k);}return "klasyczny";}private String display(String key){return color(getConfig().getString("keys."+norm(key),key));}private String path(String p){return "players."+p.toLowerCase(Locale.ROOT);}private String norm(String t){return t==null?"":t.toLowerCase(Locale.ROOT);}private int parse(String t){try{return Math.max(1,Integer.parseInt(t));}catch(Exception e){return 1;}}private String time(long ms){long m=Math.max(1,ms/60000),h=m/60,d=h/24;if(d>0)return d+"d "+(h%24)+"h";if(h>0)return h+"h "+(m%60)+"m";return m+"m";}private void save(){try{data.save(f);}catch(Exception e){e.printStackTrace();}}private String msg(String key){return color(getConfig().getString("messages.prefix","")+getConfig().getString("messages."+key,""));}private String color(String t){return ChatColor.translateAlternateColorCodes('&',t==null?"":t);}}
